import { Drawer, makeStyles, Typography } from '@material-ui/core'
import React from 'react'

const useStyle = makeStyles(theme => ({
    page: {
        background: '#f9fbfd',
        width: '100%'
    }
}));

export default function Layout({children}) {
    const classes = useStyle()

  return (
    <div>
{/* // appbar */}

{/* // sidebar */}
    
        <Drawer>
            <Typography>
                URSAC Online
            </Typography>
        </Drawer>
   
        <div className={classes.page}>
            {children}
        </div>
    </div>
  )
}
